outputs = {"list":"list","updated":"bool"}
def process(list, fieldName, fieldValue, updateField, updateValue):
    """Find struct in list by field and update another field"""
    if not list or not isinstance(list, (list, tuple)):
        return [], False
    result = [item.copy() if isinstance(item, dict) else item for item in list]
    field = str(fieldName or '')
    update_field = str(updateField or '')
    for item in result:
        if isinstance(item, dict) and field in item:
            if item[field] == fieldValue:
                item[update_field] = updateValue
                return result, True
    return result, False
